                continue
            idx = a.index(i)
            if idx != 0:
                result.append(idx+1)
                a[:idx+1] = a[:idx+1][::-1]
            result.append(i)
            a[:i] = a[:i][::-1]
        if a == sorted(a):
            print(len(result))
            print(' '.join(map(str, result)))
        else:
            print(-1)

